code = """import pandas as pd
import json

# Load data
cases = pd.DataFrame(var_call_6IT2kgtRW5a1Bo9bdjLJdM7K)
orderitems = pd.DataFrame(var_call_7Rsrjl5brNo0lXs53vw37UK9)

# Normalize IDs (strip leading '#' and whitespace)
orderitems['Id_norm'] = orderitems['Id'].astype(str).str.lstrip('#').str.strip()
cases['orderitem_norm'] = cases['orderitemid__c'].astype(str).str.lstrip('#').str.strip()

# Parse dates with UTC
cases['createddate_parsed'] = pd.to_datetime(cases['createddate'], errors='coerce', utc=True)

# Filter to past 10 months window explicitly (2020-06-10 to 2021-04-10 based on prompt)
start = pd.Timestamp('2020-06-10', tz='UTC')
end = pd.Timestamp('2021-04-10', tz='UTC')
cases = cases[(cases['createddate_parsed'] >= start) & (cases['createddate_parsed'] <= end)]

# Filter cases that are for the given product by matching orderitem id
product_orderitem_set = set(orderitems['Id_norm'].tolist())
matched_cases = cases[cases['orderitem_norm'].isin(product_orderitem_set)].copy()

if matched_cases.empty:
    result = None
else:
    matched_cases['period'] = matched_cases['createddate_parsed'].dt.to_period('M')
    counts = matched_cases.groupby('period').size().sort_index()
    mean = counts.mean()
    std = counts.std(ddof=0)
    significant_period = None
    if std == 0 or pd.isna(std):
        significant_period = None
    else:
        zscores = (counts - mean) / std
        candidates = zscores[zscores >= 2]
        if not candidates.empty:
            best = candidates.sort_values(ascending=False).index[0]
            significant_period = best
        else:
            significant_period = None
    if significant_period is None:
        result = None
    else:
        dt = significant_period.to_timestamp()
        result = dt.strftime('%B')

print("__RESULT__:")
print(json.dumps(result))"""

